import { Routes, Route, Link } from "react-router-dom";
import { useState, useEffect } from "react";
import "./App.css";

function Shops({ products, addToCart }) {
  return (
    <div>
      <h1>Shops</h1>

      <div className="container">
        <div className="shops">
          <button>Mc Donny</button>
          <button>CFK</button>
        </div>

        <div className="products">
          {products.map((p) => (
            <div key={p.id} className="product-card">
              <h3>{p.name}</h3>
              <p>{p.price} грн</p>
              <button onClick={() => addToCart(p)}>Add to cart</button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function Cart({ cart, setCart }) {
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    address: "",
  });

  const updateCount = (id, count) => {
    setCart((prev) =>
      prev.map((item) =>
        item.id === id ? { ...item, count: Number(count) } : item,
      ),
    );
  };

  const removeItem = (id) => {
    setCart((prev) => prev.filter((item) => item.id !== id));
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const total = cart.reduce((sum, item) => sum + item.price * item.count, 0);

  const handleSubmit = () => {
    if (!form.name || !form.email || !form.phone || !form.address) {
      alert("Fill all fields");
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (!emailRegex.test(form.email)) {
      alert("Invalid email");
      return;
    }

    if (cart.length === 0) {
      alert("Cart is empty");
      return;
    }

    alert("Order submitted!");

    console.log({
      customer: form,
      items: cart,
      total,
    });

    // очистка
    setCart([]);
    localStorage.removeItem("cart");

    setForm({
      name: "",
      email: "",
      phone: "",
      address: "",
    });
  };

  return (
    <div className="cart-page">
      <div className="cart-left">
        <h2>Checkout form</h2>

        <p>Name</p>
        <input
          name="name"
          placeholder="Name"
          value={form.name}
          onChange={handleChange}
        />

        <p>Email</p>
        <input
          name="email"
          placeholder="Email"
          value={form.email}
          onChange={handleChange}
        />

        <p>Phone</p>
        <input
          name="phone"
          placeholder="Phone"
          value={form.phone}
          onChange={handleChange}
        />

        <p>Address</p>
        <input
          name="address"
          placeholder="Address"
          value={form.address}
          onChange={handleChange}
        />
      </div>

      <div className="cart-right">
        <h1>Shopping Cart</h1>

        {cart.length === 0 && <p>Cart is empty</p>}

        {cart.map((item) => (
          <div key={item.id} className="cart-item">
            <h3>{item.name}</h3>
            <p>{item.price} грн</p>

            <select
              value={item.count}
              onChange={(e) => updateCount(item.id, e.target.value)}
            >
              {[1, 2, 3, 4, 5].map((num) => (
                <option key={num} value={num}>
                  {num}
                </option>
              ))}
            </select>

            <button onClick={() => removeItem(item.id)}>Remove</button>
          </div>
        ))}

        <h2>Total: {total} грн</h2>

        <button className="submit-btn" onClick={handleSubmit}>
          Submit
        </button>
      </div>
    </div>
  );
}

function App() {
  const [products] = useState([
    { id: 1, name: "Big Burger", price: 100 },
    { id: 2, name: "Small Burger", price: 80 },
  ]);

  // ✅ load from localStorage
  const [cart, setCart] = useState(() => {
    const savedCart = localStorage.getItem("cart");
    return savedCart ? JSON.parse(savedCart) : [];
  });

  // ✅ save to localStorage on change
  useEffect(() => {
    localStorage.setItem("cart", JSON.stringify(cart));
  }, [cart]);

  const addToCart = (product) => {
    setCart((prev) => {
      const existing = prev.find((p) => p.id === product.id);

      if (existing) {
        return prev.map((p) =>
          p.id === product.id ? { ...p, count: p.count + 1 } : p,
        );
      }

      return [...prev, { ...product, count: 1 }];
    });
  };

  return (
    <div>
      <nav>
        <Link to="/">Shops</Link> | <Link to="/cart">Shopping Cart</Link>
      </nav>

      <Routes>
        <Route
          path="/"
          element={<Shops products={products} addToCart={addToCart} />}
        />
        <Route path="/cart" element={<Cart cart={cart} setCart={setCart} />} />
      </Routes>
    </div>
  );
}

export default App;
